   390→    public func getLocalKeyPollingSwitchState(complete: @escaping (CarKeyPollingSwitchState, CarKeySessionError) -> Void) {
   391→        if let session = self.carKeySession {
   392→            do {
   393→                let on = try session.isPassiveEntryAvailable(forVehicle: self.vehicleIdentifier)
   394→                Log.i(tag: "carKeySession", "get passive entry on is \(on)")
   395→                if on {
   396→                    complete(.On,.None)
   397→                } else {
   398→                    complete(.Close,.None)
   399→                }
   400→            } catch {
   401→                Log.i(tag: "carKeySession", "get passive entry error: \(error.localizedDescription)")
   402→                complete(.Unknown,.Unknown)
   403→            }
   404→        } else {
   405→            complete(.Unknown,.SessionNotActive)
   406→        }
   407→    }
