   409→    private func refreshRealTimeCarKeySessionState(carKeySession: CarKeyRemoteControlSession) -> (CarKeySessionState, CarKeySessionError) {
   410→        if let vehicleReport = getVehicleReport(carKeySession: carKeySession) {
   411→            if vehicleReport.isConnected == false {
   412→                if self.state != .NotConnected {
   413→                    Log.i(tag: "carKeySession", " vechile is not connected")
   414→                }
   415→                return (.NotConnected, .BleIsNotConnected)
   416→            } else {
   417→                if self.state != .Connected {
   418→                    Log.i(tag: "carKeySession", " vechile is connected")
   419→                }
   420→                return (.Connected, .None)
   421→            }
   422→        } else {
   423→            Log.i(tag: "carKeySession", "get vechile report nil")
   424→            return (.NotConnected, .VehicleIdentifierNotFound)
   425→        }
   426→    }
   427→    
   428→    func getRealTimeCarKeySessionState() -> CarKeySessionState {
   429→        if self.state == .Connecting {
   430→            Log.i(tag: "carKeySession", "car key session is connecting")
   431→            return .Connecting
   432→        }
   433→        guard let carKeySession = self.carKeySession else {
   434→            Log.i(tag: "carKeySession", "car key session is nil")
   435→            return .NotConnected
   436→        }
   437→        let result = refreshRealTimeCarKeySessionState(carKeySession: carKeySession)
   438→        self.state = result.0
   439→        return self.state
   440→    }
   441→    
   442→    private func getVehicleReport(carKeySession: CarKeyRemoteControlSession) -> VehicleReport? {
   443→        do {
   444→            let vehicleReports = try carKeySession.vehicleReports
   445→            var report: VehicleReport?
   446→            for vehicleReport in vehicleReports {
   447→                Log.i(tag: "carKeySession", "getVehicleReport identifier: \(vehicleReport.identifier.lowercased()), \(self.vehicleIdentifier.lowercased())")
   448→                if vehicleReport.identifier.lowercased() == self.vehicleIdentifier.lowercased() {
   449→                    self.vehicleIdentifier = vehicleReport.identifier
   450→                    report = vehicleReport
   451→                    break
   452→                }
   453→            }
   454→            if report == nil {
   455→                Log.i(tag: "carKeySession", "getVehicleReport not found for vehicleIdentifier: \(self.vehicleIdentifier)")
   456→            }
   457→            return report
   458→        } catch {
   459→            Log.i(tag: "carKeySession", "getVehicleReport error: \(error.localizedDescription)")
   460→            return nil
   461→        }
   462→    }
   463→    
