import CarKey
import UIKit
import Combine
import CryptoSwift

enum CarKeySessionError: Int, Error, Codable, CustomStringConvertible {
    case None = 0;
    case CarKeySessionIsNil
    case BleIsNotConnected
    case VehicleIdentifierIsNotEqual
    case VehicleIdentifierNotFound
    case AnotherRequestInProgress
    case SessionNotActive
    case FunctionUnknown
    case SecurityViolation
    case MessageTooLong
    case RequestTimedOut
    case ClientInBackground
    case FeatureNotSupported
    case CarKeySessionIsConnecting
    case CarKeySessionIsDisconnecting
    case TaskTimedOut
    case Block
    case Unknown

     var description: String {
        switch self {
        case .None:
            return "None"
        case .CarKeySessionIsNil:
            return "CarKeySessionIsNil"
        case .BleIsNotConnected:
            return "BleIsNotConnected"
        case .VehicleIdentifierIsNotEqual:
            return "VehicleIdentifierIsNotEqual"
