import Foundation
import Combine

@available(iOS 18.0, *)
class BLEKeyCarKeySessionHandler : BLEHandler  {

    let cccKeyId: String
    let cccVid: String
    var bleSendFlow: BleSendDataFlow?
    var writeDataCancellables: AnyCancellable?

    lazy var carKeySession: CarKeySessionAccesser = {
        return CarKeySessionAccesser(vehicleIdentifier: self.cccVid, delegate: self)
    }()

    init(name: String, macAddress: String?, cccVid: String, cccKeyId: String, dataParser: BLEKeyParserProtocol) {
        self.cccKeyId = cccKeyId
        self.cccVid = cccVid
        super.init(ssidPrefix: "", name: name, macAddress: macAddress ?? "no need", dataParser: dataParser)
        self.addCarKeyStateObserver()
    }

    func addCarKeyStateObserver() {
        self.carKeySession.stateSubject.sink {[weak self] state in
            guard let self = self else {
                Log.i(tag: "carKeySession", "self is deallocated")
                return
            }
            Log.i(tag: "carKeySession", "carkey蓝牙连接状态：", state)
            if state == .NotConnected {
                self.state = .NotConnected
                self.disconnect()
                NotificationCenter.default.post(name: VehicleNotification.kGetCarKeyPassiveEntrySwitchResult, object: nil, userInfo: ["pollingState": CarKeyPollingSwitchState.Unknown.rawValue, "error": CarKeySessionError.BleIsNotConnected.rawValue])
            } else if state == .Connecting {
                self.state = .Connecting
            } else if state == .Connected {
                self.state = .Available
                self.carKeySession.getLocalKeyPollingSwitchState { state, error in
                    NotificationCenter.default.post(name: VehicleNotification.kGetCarKeyPassiveEntrySwitchResult, object: nil, userInfo: ["pollingState": state.rawValue, "error": error.rawValue])
                }
            }
        }.store(in: &cancellables)
    }

    deinit {
        Log.i("蓝牙 BLEHandler.deinit mac:", name)
        disconnect()
    }

    override func connect() {
        guard self.state == .NotConnected else {
            Log.i(tag: "carKeySession", "state is not notConnected")
            return
        }
        self.carKeySession.startCarKeySession(timeOut: 6) { [weak self] error in
            guard let self = self else {
                Log.i(tag: "carKeySession", "self is deallocated")
                return
            }
            Log.i(tag: "carKeySession", "startCarKeySession error:", error)
        }
    }

    override func disconnect() {
        Log.i("bleDisconnect mac:", name)
        self.bleSendFlow?.cancelQueueAllTask()
        self.bleSendFlow = nil
        self.carKeySession.endCarKeySession { error in
            Log.i(tag: "carKeySession", "endCarKeySession error:", error)
        }
        self.state = .NotConnected
    }

    override func startAuth() {
        Log.i("carkey relay system safe:", name)
    }

    override func send(data: BleSendData, success: SuccessCallback?, failed: FailedCallback?) {
        if self.bleSendFlow == nil {
            self.bleSendFlow = BleSendDataFlow(dataSendImp: self)
        }
        self.bleSendFlow?.write(params: data, success: success, failed: failed)
    }

    override func getActualConnectState() -> BLEConnectionState {
        let state = self.carKeySession.getRealTimeCarKeySessionState()
        if state == .NotConnected {
            return .NotConnected
        } else if state == .Connecting {
            return .Connecting
        } else if state == .Connected {
            return .Available
        } else {
            return .NotConnected
        }
    }

    override func isInBackground(inBackground: Bool) {
        super.isInBackground(inBackground: inBackground)
        self.carKeySession.getLocalKeyPollingSwitchState { state, error in
            NotificationCenter.default.post(name: VehicleNotification.kGetCarKeyPassiveEntrySwitchResult, object: nil, userInfo: ["pollingState": state.rawValue, "error": error.rawValue])
        }
    }

    override func getReconnectCount() -> Int {
        return 20
    }

    override func getReconnectInterval() -> TimeInterval {
        return 3
    }

}

@available(iOS 18.0, *)
extension BLEKeyCarKeySessionHandler: BLESendDataFlowProtocol {

    func sendData(data: Data, writeType: BleDeviceWriteType, timeOut: TimeInterval, success: SuccessCallback?, failed: FailedCallback?) {
        Log.i("[蓝牙写数据]", "写数据开始", data.description)
        self.carKeySession.sendPassthroughtData(data: data, timeOut: timeOut) { error in
            if error == .None {
                success?()
            } else {
                if error == .BleIsNotConnected {
                    failed?(.bleNotConnect)
                } else if error == .RequestTimedOut {
                    failed?(.writeTimeOut)
                } else {
                    failed?(.unowned)
                }
            }
        }
    }

    func trackingSendDataFull(count: Int) {
        Log.i("trackingSendDataFull count:", count)
    }
}

@available(iOS 18.0, *)
extension BLEKeyCarKeySessionHandler: CarKeySessionEventDelegate {

    func carKeyFunctionExceptionError(error: CarKeySessionError) {
        Log.i("carKeyFunctionExceptionError:", error)
        NotificationCenter.default.post(name: VehicleNotification.CarKeyNeedRefesh, object: nil)
    }

    func didReceivePassThroughData(data: Data) {
        self.dataParser.parseBleData(data)
    }

    func reportBlockingException(data: CarKeyExceptionObj) {
        NotificationCenter.default.post(name: VehicleNotification.CarKeySessionExceptionReport, object: data)
    }
}
